{
  "部队档案": {
    "番号": "第207卫士训练部队 (207th Training Unit)",
    "正式名称": "日本帝国陆军 白陵基地 第207卫士训练部队 (Imperial Japanese Army Hakuryo Base 207th Eishi Training Unit)",
    "概要": "驻扎于日本帝国白陵基地的精英卫士训练部队。其主要职责是为即将奔赴残酷战场的菜鸟卫士们提供最后的、也是最关键的战术机驾驶与战斗技巧训练。该部队以其极度严苛和高淘汰率的训练课程而闻名，旨在将受训者从普通学生转变为能够直面BETA威胁、心志坚定的战士。在《Alternative》的故事中，这里是主角白银武重塑自我、从零开始再次接受卫士训练的地方，也是他与未来战友们建立羁绊的核心舞台。",
    "详细信息": [
      {
        "标题": "训练理念与现实",
        "内容": "第207部队的训练远不止于操作战术机。在指挥官神宫寺真理绘教官的铁腕指导下，训练生们被反复灌输“任务优先于一切”的原则，包括战友的生命。训练模拟的伤亡率被刻意设定得极高，目的是让训练生们在奔赴前线前就习惯于失去同伴的痛苦与绝望，并学会如何在这种极端压力下继续执行任务。这种地狱般的训练确保了只有最坚韧、最适应战场法则的人才能毕业。"
      },
      {
        "标题": "与A-01“女武神”的关联",
        "内容": "在“路西法行动”准备期间，联合国的王牌部队A-01第9中队“女武神”也被派遣至白陵基地，与第207训练部队进行共同训练。其目的在于让双方，特别是作为核心的白银武，能够与“女武神”的成员们进行磨合，建立战术协同性。这种安排使得207训练部队的训练生们有机会近距离接触传说中的王牌卫士，并在联合演习中亲身体验最高水平的战斗。"
      }
    ],
    "主要人员": {
      "指挥官与教官": [
        {
          "姓名": "神宫寺 真理绘 (Jinguuji Marimo)",
          "军衔": "中尉",
          "职务": "第207卫士训练部队指挥官 / 总教官",
          "简介": "一位以严厉和冷酷著称的精英教官，但其严苛的背后是对部下生命负责的深沉情感。她是白银武等人的主要训练负责人。"
        },
       ],
