{
  "name_jp": "パウル・ラダビノッド",
  "name_romaji": "Pōru Radhabinoddo",
  "name_cn": "保罗·拉达比诺德",
  "birthday": "12月7日",
  "appearance": {
    "hair": "灰色短发",
    "eyes": "红色",
    "physique": "成年男性，高挑，平均体型，散发着威严、领导力和国际视野的氛围"
  },
  "biography": "作为联合国横滨基地的司令官，准将保罗·拉达比诺德是基地的第一任指挥官，自1999年起负责管理基地的防御事务。尽管神宫司优子实际运营基地，但他拥有最高军事权威，对所有军事事项有最终决定权。他与优子关系密切，完全知晓基地的秘密研究，是Alternative IV计划的坚定支持者。在Muv-Luv Alternative中，他向207训练部队发表两次著名演讲：一次在日本政变后毕业典礼上，哀悼横滨基地事件中的损失并激励幸存者；另一次在樱花作战前，鼓舞士气。他监督了横滨基地的成功防御，保护了00单位，尽管基地几近毁灭，几乎全军覆没。作为印度人，他象征着国际合作与人类团结。性格坚定、富有魅力，常以激昂演说激励部下。",
  "quotes": [
    {
      "character": "保罗·拉达比诺德",
      "line": "諸君、私たちは人類の最後の防衛線だ。負けるわけにはいかない！ (诸君，我们是人类最后的防线。绝不能失败！)"
    },
    {
      "character": "保罗·ラダビノッド",
      "line": "Alternative IVは人類の未来を賭けた賭けだ。私たちはそれを信じ、守る。 (Alternative IV是赌上人类未来的赌注。我们相信它，并守护它。)"
    },
    {
      "character": "保罗·拉ダビノ德",
      "line": "失われた命を無駄にしないために、生き残った者たちは前へ進むのだ。 (为了不让逝去的生命白费，幸存者们必须前进。)"
    },
    {
      "character": "保罗·拉达比诺德",
      "line": "横浜基地は壊滅したが、私たちの意志は不滅だ。桜花作戦、成功させろ！ (横滨基地虽已毁灭，但我们的意志永存。樱花作战，必须成功！)"
    },
    {
      "character": "保罗·拉ダビノ德",
      "line": "国際協力なくして、人類の勝利はない。共に戦おう。 (没有国际合作，就没有人类的胜利。让我们一起战斗吧。)"
    }
  ]
}

