{
  "name_jp": "イリーナ・ピアティフ",
  "name_romaji": "Irina Piatih",
  "name_cn": "伊莉娜·皮亚蒂夫",
  "birthday": "9月12日",
  "appearance": {
    "hair": "金色短发，鲍勃头，带尖刘海",
    "eyes": "蓝色",
    "physique": "成年女性体型，苗条，散发着专业、冷静且可靠的氛围"
  },
  "biography": "作为联合国军的中尉，伊莉娜·皮亚蒂夫担任横滨基地的通讯官，同时是副司令官神宫司优子的秘书。她来自波兰。在Muv-Luv Alternative中，她在游戏开头的引言序列中首次出现，与Bravo-1进行通讯，这是玩家首次接触到âge著名的英语台词。她协助优子管理基地事务，并间接参与Alternative IV计划。在Altered Fable中，她作为外国教师出现，对白银武表现出浓厚兴趣。她以Elena Piatif的别名为英语粉丝所知。性格专业、可靠，常在高压环境下保持冷静。",
  "quotes": [
    {
      "character": "伊莉娜·皮亚蒂夫",
      "line": "通信を確保せよ。基地の安全が優先だ。 (确保通讯。基地的安全是优先的。)"
    },
    {
      "character": "伊莉娜·皮亚蒂夫",
      "line": "副司令の指示を厳守せよ。私がサポートする。 (严格遵守副司令的指示。我会支持的。)"
    },
    {
      "character": "伊莉娜·皮亚蒂夫",
      "line": "ポーランドの血が、私を強くする。 (波兰的血统，让我坚强。)"
    },
    {
      "character": "伊莉娜·皮亚蒂夫",
      "line": "Alternative IVの成功が、人類の希望だ。 (Alternative IV的成功，是人类的希望。)"
    },
    {
      "character": "伊莉娜·皮亚蒂夫",
      "line": "冷静に、正確に。ミスは許されない。 (冷静地，准确地。不允许失误。)"
    }
  ]
}

