28.content:
{
  "武器装备": [
    {
      "名称": "65式近距离战斗短刀",
      "描述": "成为不知火为首的日本军战术机标准武器而使用的近距离战斗短刀。通常收纳在前臂外侧的收纳模块“刀鞘”中，不到1秒即可展开伸长的副臂会将其装备在主臂机械臂上。副臂展开角度非常广，左右机械臂都可装备。"
    },
    {
      "名称": "00式近距离战斗短刀",
      "描述": "F-4引进以来，日本一边坚持着美国发起的“使用机械臂的武器通用性”这一战术机使用上不成文的规定，一边基于独自使用思想在开发周边装备。但是，城内省关注的是采用装甲冲角、马达刀板和刀刃边缘装甲之类固定式辅助武器的欧洲、苏联军机在近距离密集战斗中的高生存性。经过对实战数据的研究，认识到不占用机械臂的固定武器有效性后，决定将其用在开发中的武御雷上。00式近距离战斗短刀正是以此为前提基础而开发的武装之一。"
    },
    {
      "名称": "74式近距离战斗长刀",
      "描述": "日本帝国军制式采用的近距离战斗长刀。超碳制。刀柄沿着刀刃方向内翻，这种形状适于敲打，举刀一斩也有可能切断突击级和要塞级BETA的坚固外壳。该武器在1972年日本帝国决定引进F-4的同时，作为专用装备（美国名称叫CIWS-2A）向美国下单，不过受到欧洲战况恶化的影响，机体配备优先顺序被降格，于是就只是武器在1974年先行配备。"
    },
    {
      "名称": "92式多目的追加装甲",
      "描述": "机械臂握持的护盾。由耐热防弹复合装甲材料构成，并施以对激光蒸发涂膜加工。战术机主要用高机动力来回避攻击，但在密集战中无法充分回避时，以及在压制支援时因为搭载多目的自主制导弹系统导致机动力低下的情况使该护盾。下部可动部成直角展开，还能成为打击武器和土木作业用的推土铲使用。盾的表面搭载有六边形的定向炸药。在排除贴上来的战车级BETA时很有效，同时殴打敌方时引发爆炸能给予其高效损害。但是炸药搭载数量有限，敲打攻击时追加装甲本身也会出现损伤，所以使用上属于可舍弃掉的装备。"
    },
    {
      "名称": "87式突击炮",
      "描述": "日本帝国军采用的突击炮。和普通突击炮的36毫米供弹方式有很大不同，弹夹是水平于枪身安装的。弹夹不凸起，对使用有好处。使用120毫米弹药与36毫米弹药。"
    },
    {
      "名称": "87式支援突击炮",
      "描述": "87式突击炮的120毫米滑膛炮换装为高精度瞄准镜，36毫米长管化的突击炮。可以从事比普通突击炮更高精度的炮击，按照前卫的支援炮击要求，成为打击支援机和炮击支援机的主装备。"
    },
    {
      "名称": "74式可动武器担架系统",
      "描述": "为携带预备武器的担架系统，日本帝国机上搭载的是74式可动武器担架系统。担架部分更换后能搭载丰富多样的武器。担架本身也有很大的可动范围，可以说是战术机的“第3、第4手臂”。",
      "模块": [
        {
          "名称": "Blade Mount",
          "描述": "74式可动武器担架系统上在搭载长刀时使用的担架。长刀上有4处吻合片用螺栓固定。"
        },
        {
          "名称": "Gun Mount",
          "描述": "74式可动武器担架系统中用来搭载突击炮的担架。不仅能把突击炮转移到战术机的机械臂上，担架还能自动运作独立射击,还可进行辅助臂的换弹。"
        }
      ]
    },
    {
      "名称": "S-11",
      "描述": "SD-SYSTEM(SELF-DESTRUCTION-SYSTEM)战术机内部搭载的具有小型战术核弹破坏力的高性能炸弹。名义上是用来破坏巢穴反应炉的，但另一面是无法行动的战术机的卫士所使用的自裁武器。为了高效破坏反应炉，或者自裁时避免己方受牵连，所以爆炸是指向性的，不过炸药配置调整过后，也可以非指向性使用。另外，美国采用了使用G弹为前提的军事思想后，美军的战术机就不再搭载S-11了。"
    }
  ]
}

29.content:
{
  "武器装备": [
    {
      "名称": "CIWS-1A",
      "描述": "F-15系列的武器收纳模块装备在膝部，由机械臂自动装备，这是标准规格。短刀装备所需时间这方面比副臂展开型要差点，但部件数量少并且构造简单这使其在整备性和可靠性方面胜出。另外，武器收纳模块除了短刀，还能收纳突击炮的各种预备弹夹等。"
    },
    {
      "名称": "CIWS-1B",
      "描述": "给F-22专用开发的折叠式短刀，在装备到机械臂之前自动展开，如此即可迅速装备。作为武器而言，强度比固定式的要差，不过这是重视收纳体积使然，另外这也反映出浓厚的使用思想“F-22在近距离战斗中要到不得不使用短刀，这情况基本不会出现”。"
    },
    {
      "名称": "XCIWS-2B",
      "描述": "YF-23标准装备的近距离战长刀。利用CIWS-2A（74式近距离战斗长刀）的制造技术而打造的，不过ATSF计划中并没有被YF-23采用，相伴的XCIWS-2B也没有制式化。"
    },
    {
      "名称": "AMWS-21",
      "描述": "AMWS是由36毫米突击机关炮和120毫米滑膛炮构成的美军战术机的主武器。为了计算射击目标和距离将情报传递给FCS，激光测距装置也是一体化的。120毫米滑膛炮是模块化的，所以能根据任务换装其他武器。炮本身用的是无后坐力炮原理，发射时抑制初速以减轻后坐力，另一方面因为能使用火箭推进炮弹，所以弹速、射程距离都得以确保。射程超过3000米，不过在接近射程极限的位置所期待的命中率、装甲穿透力都降低了。另外，36毫米、120毫米炮弹和相当于弹壳的部分一起形成弹药，成为无壳弹，所以射击时并不抛壳。这些炮弹是世界通用规格的，弹夹形状合适的话，不同机种间可以毫无问题的使用。"
    },
    {
      "名称": "WS-16C 突击炮",
      "描述": "和世界最初的战术机F-4实战配备一起被采用的标准武器。初期型WS-16上滑膛炮口径是105毫米，机关炮口径是20毫米，而改良型WS-16B变更为更高火力的120毫米滑膛炮、36毫米机关炮。接着，为提高可靠性而改进的WS-16C经过微调，成为美军第1~2代战术机的主力装备。随着AMWS-21实用化，在美国国内的制造终止了，不过美军内一部分机体还在使用它。"
    }
  ]
}

